    return parent[x]
def union(x, y):
    rootx, rooty = find(x), find(y)
    if rootx != rooty:
        if rank[rootx] > rank[rooty]:
            parent[rooty] = rootx
        elif rank[rootx] < rank[rooty]:
            parent[rootx] = rooty
        else:
            parent[rooty] = rootx
            rank[rootx] += 1
for _ in range(E):
